// Парсим ответ OpenAI и рендерим красивый HTML email
const openaiRaw = $input.first().json;
const content = openaiRaw.choices?.[0]?.message?.content || '{}';

let plan;
try {
  plan = JSON.parse(content);
} catch (e) {
  // Иногда модель оборачивает в ```json — пробуем вытащить
  const m = content.match(/\{[\s\S]+\}/);
  plan = m ? JSON.parse(m[0]) : { title: 'Ошибка', summary: 'Не удалось распарсить ответ AI', days: [], tips: [], budget_estimate: '' };
}

const meta = $('Validate & Normalize').first().json;

const esc = (s) => String(s ?? '').replace(/[&<>"']/g, (c) => ({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[c]));

const dayBlocks = (plan.days || []).map((d) => `
  <tr><td style="padding: 24px 0 8px; border-top: 1px solid #e6e2d8;">
    <span style="display:inline-block; font-family: Georgia, serif; font-size: 14px; color: #7A1F2B; letter-spacing: 0.1em; font-weight: 600;">ДЕНЬ ${esc(d.day)}</span>
    <h3 style="margin: 4px 0 16px; font-family: Georgia, serif; font-size: 22px; font-style: italic; font-weight: 400; color: #0E1B3A; line-height: 1.25;">${esc(d.title)}</h3>
    <ul style="margin: 0; padding: 0 0 0 4px; list-style: none; color: #2a2a2a; font-size: 15px; line-height: 1.6;">
      ${(d.items || []).map((p) => `<li style=\"padding: 6px 0 6px 18px; position: relative;\"><span style=\"position:absolute; left:0; color:#7A1F2B;\">·</span>${esc(p)}</li>`).join('')}
    </ul>
  </td></tr>`).join('');

const tipsBlock = (plan.tips || []).length
  ? `<tr><td style="padding: 24px 0; border-top: 1px solid #e6e2d8;">
      <span style="display:inline-block; font-family: Georgia, serif; font-size: 12px; color: #7A1F2B; letter-spacing: 0.16em; text-transform:uppercase; font-weight:600;">Советы</span>
      <ul style="margin: 12px 0 0 0; padding-left: 20px; color: #2a2a2a; font-size: 15px; line-height: 1.6;">
        ${plan.tips.map((t) => `<li style=\"padding: 4px 0;\">${esc(t)}</li>`).join('')}
      </ul>
    </td></tr>` : '';

const html = `<!doctype html>
<html lang="ru">
<head><meta charset="utf-8"><title>${esc(plan.title || 'Маршрут по Крыму')}</title></head>
<body style="margin:0; padding: 32px 16px; background: #FAF6EE; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; color: #1a1a1a;">
  <table role="presentation" cellspacing="0" cellpadding="0" style="max-width: 640px; margin: 0 auto; background: #fff; border: 1px solid #e6e2d8;">
    <tr><td style="padding: 32px 32px 16px; text-align: center; border-bottom: 1px solid #e6e2d8;">
      <span style="font-size: 12px; letter-spacing: 0.16em; text-transform: uppercase; color: #6b6b6b;">Крым · издание о полуострове</span>
      <h1 style="margin: 16px 0 8px; font-family: Georgia, serif; font-style: italic; font-weight: 400; font-size: 32px; line-height: 1.15; color: #0E1B3A;">${esc(plan.title || 'Ваш маршрут')}</h1>
      <p style="margin: 8px 0 0; color: #6b6b6b; font-size: 13px;">${esc(meta.cityName)} · ${esc(meta.days)} дн. · ${esc(meta.compName)} · ${esc(meta.transportName)}</p>
    </td></tr>
    <tr><td style="padding: 24px 32px;">
      <p style="margin: 0; font-size: 16px; line-height: 1.6; color: #2a2a2a;">${esc(plan.summary || '')}</p>
      ${plan.total_km ? `<p style=\"margin: 12px 0 0; color: #6b6b6b; font-size: 13px;\">Общий пробег: ~${esc(plan.total_km)} км</p>` : ''}
    </td></tr>
    <tr><td style="padding: 0 32px;">
      <table role="presentation" cellspacing="0" cellpadding="0" style="width:100%;">
        ${dayBlocks}
        ${tipsBlock}
        ${plan.budget_estimate ? `<tr><td style=\"padding: 24px 0; border-top: 1px solid #e6e2d8;\"><span style=\"font-family: Georgia, serif; font-size: 12px; letter-spacing: 0.16em; text-transform: uppercase; color: #7A1F2B; font-weight: 600;\">Бюджет</span><p style=\"margin: 8px 0 0; font-size: 15px; color: #2a2a2a; line-height: 1.5;\">${esc(plan.budget_estimate)}</p></td></tr>` : ''}
      </table>
    </td></tr>
    <tr><td style="padding: 24px 32px 32px; background: #FAF6EE; text-align: center; font-size: 12px; color: #6b6b6b;">
      Это базовая версия маршрута. Цены и расписание уточняйте на официальных сайтах объектов.
      <br><br>
      <a href="https://welcomecrimea.ru/" style="color: #7A1F2B; text-decoration: none;">welcomecrimea.ru</a>
    </td></tr>
  </table>
</body></html>`;

return [{
  json: {
    html,
    subject: `Ваш маршрут: ${plan.title || meta.cityName + ', ' + meta.days + ' дней'}`,
    plan,
    meta
  }
}];
